    operations = [
        ["prefix_sum", 3],
        ["range_sum", 1, 4],
        ["update", 2, 15.00],
        ["prefix_sum", 3],
        ["range_sum", 1, 4],
        ["range_sum", 0, 5]
    ]
    result = fenwick_tree_stock_analyzer(prices, operations)
    print(result)
